import { fmt } from "./parseItem";

const SANS = "Unbounded, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif";
const MONO = "Geist Mono, ui-monospace, SFMono-Regular, Menlo, Consolas, monospace";

function themeColors() {
  const isDark = document.documentElement.classList.contains("dark");
  const t = {
    bg: isDark ? "#0A0C10" : "#F5F0EA",
    text: isDark ? "#ffffff" : "#18181b",
    muted: isDark ? "#71717a" : "#52525b",
    subtle: isDark ? "#a1a1aa" : "#71717a",
    green: isDark ? "#10b981" : "#047857",
    greenSoft: isDark ? "#34d399" : "#059669",
    amber: isDark ? "#fbbf24" : "#b45309",
    red: isDark ? "#f87171" : "#dc2626",
    gridLine: isDark ? "rgba(255,255,255,0.055)" : "rgba(0,0,0,0.06)",
    cardBg: isDark ? "rgba(255,255,255,0.025)" : "rgba(0,0,0,0.03)",
    cardBorder: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.08)",
    glowGreen: isDark ? "rgba(16,185,129,0.20)" : "rgba(5,150,105,0.12)",
    glowAmber: isDark ? "rgba(245,158,11,0.10)" : "rgba(180,83,9,0.08)",
  };
  return t;
}

const VARIANTS = {
  item: { width: 1200, height: 630, compose: composeItemCard },
  compact: { width: 1080, height: 1080, compose: composeCompactCard },
};

export const EXPORT_VARIANTS = Object.keys(VARIANTS);

function roundRect(ctx, x, y, w, h, r) {
  const radius = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
}

function fillRoundRect(ctx, x, y, w, h, r, fill, stroke = null) {
  roundRect(ctx, x, y, w, h, r);
  ctx.fillStyle = fill;
  ctx.fill();
  if (stroke) {
    ctx.strokeStyle = stroke;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

function drawLabel(ctx, text, x, y, color) {
  ctx.font = `700 11px ${MONO}`;
  ctx.fillStyle = color;
  ctx.fillText(String(text || "").toUpperCase(), x, y);
}

function drawTextLines(ctx, text, x, y, maxWidth, lineHeight, maxLines) {
  const words = String(text || "").split(/\s+/).filter(Boolean);
  const lines = [];
  let line = "";
  let consumed = 0;
  for (const word of words) {
    const next = line ? `${line} ${word}` : word;
    if (ctx.measureText(next).width <= maxWidth || !line) {
      line = next;
      consumed += 1;
      continue;
    }
    lines.push(line);
    line = word;
    consumed += 1;
    if (lines.length >= maxLines) break;
  }
  if (line && lines.length < maxLines) lines.push(line);
  if (lines.length === maxLines && consumed < words.length) {
    let last = lines[lines.length - 1];
    while (ctx.measureText(`${last}...`).width > maxWidth && last.length > 1) {
      last = last.slice(0, -1);
    }
    lines[lines.length - 1] = `${last}...`;
  }
  lines.forEach((value, index) => ctx.fillText(value, x, y + index * lineHeight));
  return lines.length * lineHeight;
}

function drawChip(ctx, text, x, y, color, bg, border) {
  ctx.font = `800 18px ${MONO}`;
  const width = Math.ceil(ctx.measureText(text).width) + 18;
  fillRoundRect(ctx, x, y - 22, width, 30, 4, bg, border);
  ctx.fillStyle = color;
  ctx.fillText(text, x + 9, y);
  return width;
}

function drawGrid(ctx, width, height, color) {
  ctx.save();
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  for (let x = 0; x <= width; x += 40) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, height);
    ctx.stroke();
  }
  for (let y = 0; y <= height; y += 40) {
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(width, y);
    ctx.stroke();
  }
  ctx.restore();
}

function drawGlow(ctx, x, y, radius, color, width, height) {
  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
  gradient.addColorStop(0, color);
  gradient.addColorStop(1, "rgba(0,0,0,0)");
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, width, height);
}

function fmtStamp(ms) {
  const d = new Date(ms || Date.now());
  const yyyy = d.getUTCFullYear();
  const mm = String(d.getUTCMonth() + 1).padStart(2, "0");
  const dd = String(d.getUTCDate()).padStart(2, "0");
  const hh = String(d.getUTCHours()).padStart(2, "0");
  const mi = String(d.getUTCMinutes()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd} ${hh}:${mi} UTC`;
}

function trendLabel(trend, t) {
  if (trend === "up") return { label: "Rising", color: t.green };
  if (trend === "down") return { label: "Falling", color: t.red };
  return { label: "Stable", color: t.subtle };
}

function drawSparkline(ctx, series, median, x, y, w, h, t) {
  fillRoundRect(ctx, x, y, w, h, 12, t.cardBg, t.cardBorder);
  const data = Array.isArray(series) ? series.filter((p) => Number(p?.v) > 0) : [];
  if (data.length < 2) {
    ctx.font = `700 13px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText(data.length === 1 ? "1 PT" : "NOT ENOUGH DATA", x + 28, y + h / 2);
    return;
  }

  const padL = 54;
  const padR = 20;
  const padT = 24;
  const padB = 36;
  const innerW = w - padL - padR;
  const innerH = h - padT - padB;
  const values = data.map((p) => Number(p.v));
  let min = Math.min(...values, Number(median || Infinity));
  let max = Math.max(...values, Number(median || 0));
  const span = max - min || 1;
  min -= span * 0.08;
  max += span * 0.08;
  const range = max - min || 1;

  const points = data.map((p, index) => [
    x + padL + (innerW * index) / (data.length - 1),
    y + padT + innerH - ((Number(p.v) - min) / range) * innerH,
  ]);

  ctx.save();
  ctx.strokeStyle = t.gridLine;
  ctx.fillStyle = t.muted;
  ctx.font = `10px ${MONO}`;
  [min, min + range / 2, max].forEach((tick) => {
    const ty = y + padT + innerH - ((tick - min) / range) * innerH;
    ctx.beginPath();
    ctx.moveTo(x + padL, ty);
    ctx.lineTo(x + padL + innerW, ty);
    ctx.stroke();
    ctx.textAlign = "right";
    ctx.fillText(fmt(tick), x + padL - 8, ty + 3);
  });
  ctx.textAlign = "left";

  if (median > 0) {
    const medianY = y + padT + innerH - ((median - min) / range) * innerH;
    ctx.strokeStyle = t.amber;
    ctx.setLineDash([6, 5]);
    ctx.beginPath();
    ctx.moveTo(x + padL, medianY);
    ctx.lineTo(x + padL + innerW, medianY);
    ctx.stroke();
    ctx.setLineDash([]);
  }

  ctx.beginPath();
  points.forEach(([px, py], index) => {
    if (index === 0) ctx.moveTo(px, py);
    else ctx.lineTo(px, py);
  });
  const last = points[points.length - 1];
  const first = points[0];
  ctx.lineTo(last[0], y + padT + innerH);
  ctx.lineTo(first[0], y + padT + innerH);
  ctx.closePath();
  const fill = ctx.createLinearGradient(0, y + padT, 0, y + padT + innerH);
  fill.addColorStop(0, t.green + "59");
  fill.addColorStop(1, t.green + "00");
  ctx.fillStyle = fill;
  ctx.fill();

  ctx.beginPath();
  points.forEach(([px, py], index) => {
    if (index === 0) ctx.moveTo(px, py);
    else ctx.lineTo(px, py);
  });
  ctx.strokeStyle = t.green;
  ctx.lineWidth = 3;
  ctx.lineJoin = "round";
  ctx.lineCap = "round";
  ctx.stroke();

  for (const [px, py] of points.slice(0, -1)) {
    ctx.fillStyle = t.green;
    ctx.beginPath();
    ctx.arc(px, py, 3.5, 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.fillStyle = t.greenSoft;
  ctx.beginPath();
  ctx.arc(last[0], last[1], 5, 0, Math.PI * 2);
  ctx.fill();

  const labelDate = (p) => new Date(p.ts || p.t || Date.now()).toLocaleDateString(undefined, { month: "short", day: "numeric" });
  ctx.fillStyle = t.muted;
  ctx.font = `10px ${MONO}`;
  ctx.textAlign = "center";
  ctx.fillText(labelDate(data[0]), points[0][0], y + h - 13);
  ctx.fillText(labelDate(data[Math.floor(data.length / 2)]), points[Math.floor(points.length / 2)][0], y + h - 13);
  ctx.fillText(labelDate(data[data.length - 1]), last[0], y + h - 13);
  ctx.restore();
}

function drawTopSellers(ctx, sellers, y, t) {
  drawLabel(ctx, "Top sellers", 56, y, t.muted);
  const list = Array.isArray(sellers) ? sellers.slice(0, 3) : [];
  if (list.length === 0) {
    ctx.font = `600 14px ${SANS}`;
    ctx.fillStyle = t.muted;
    ctx.fillText("No active listings.", 56, y + 44);
    return;
  }

  const cardW = 356;
  list.forEach((seller, index) => {
    const x = 56 + index * (cardW + 12);
    fillRoundRect(ctx, x, y + 18, cardW, 64, 10, t.cardBg, t.cardBorder);
    ctx.font = `700 11px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText(`#${index + 1}`, x + 12, y + 55);

    ctx.font = `800 15px ${SANS}`;
    ctx.fillStyle = t.text;
    drawTextLines(ctx, seller.name || "Unknown", x + 44, y + 43, 170, 16, 1);

    const label = seller.label || "Neutral";
    const labelColor = label === "Flagged" ? t.red : label === "Suspicious" ? t.amber : label === "Trustworthy" ? t.greenSoft : t.subtle;
    ctx.font = `700 9px ${MONO}`;
    ctx.fillStyle = labelColor;
    ctx.fillText(label.toUpperCase(), x + 44, y + 63);

    ctx.font = `800 17px ${MONO}`;
    ctx.fillStyle = t.green;
    ctx.textAlign = "right";
    ctx.fillText(fmt(seller.unitPrice || 0), x + cardW - 14, y + 56);
    ctx.textAlign = "left";
  });
}

function drawHeader(ctx, data, width, t) {
  ctx.font = `800 13px ${MONO}`;
  ctx.fillStyle = t.green;
  ctx.fillText("CASTIA — LIVE", 74, 50);
  ctx.fillStyle = t.green;
  ctx.beginPath();
  ctx.arc(62, 46, 4, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = t.muted;
  ctx.textAlign = "right";
  ctx.fillText(fmtStamp(data.generatedAt), width - 56, 50);
  ctx.textAlign = "left";
}

function drawFooter(ctx, width, height, t) {
  ctx.font = `700 10px ${MONO}`;
  ctx.fillStyle = t.muted;
  ctx.fillText("CASTIA MARKET INSIGHT — BY LEKTO_", 56, height - 18);
  ctx.textAlign = "right";
  ctx.fillText("CMI", width - 56, height - 18);
  ctx.textAlign = "left";
}

function composeItemCard(ctx, data, width, height) {
  const t = themeColors();
  drawHeader(ctx, data, width, t);

  const category = `${data.category || "Item"}${data.tier > 0 ? ` — Tier ${data.tier}` : ""}`;
  drawLabel(ctx, category, 56, 124, t.subtle);

  ctx.font = `900 54px ${SANS}`;
  ctx.fillStyle = t.text;
  const titleHeight = drawTextLines(ctx, data.name || "Unknown item", 56, 175, 540, 58, 2);
  let chipX = 56;
  const chipY = 190 + Math.min(titleHeight, 116);
  if (data.tier > 0) {
    chipX += drawChip(ctx, `T${data.tier}`, chipX, chipY, t.amber, t.amber + "1A", t.amber + "66") + 8;
  }
  for (const modifier of (data.modifiers || []).slice(0, 3)) {
    chipX += drawChip(ctx, String(modifier).toUpperCase(), chipX, chipY, t.greenSoft, t.green + "1A", t.green + "66") + 8;
  }

  drawLabel(ctx, "Median price", 56, 330, t.muted);
  ctx.font = `900 78px ${SANS}`;
  ctx.fillStyle = t.green;
  ctx.fillText(data.median > 0 ? fmt(data.median) : "—", 56, 410);

  const trend = trendLabel(data.trend, t);
  ctx.font = `800 16px ${MONO}`;
  ctx.fillStyle = trend.color;
  ctx.fillText(trend.label.toUpperCase(), 56, 444);

  ctx.font = `700 11px ${MONO}`;
  ctx.fillStyle = t.subtle;
  ctx.fillText("CONFIDENCE", 56, 482);
  ctx.fillText("SAMPLES", 270, 482);
  ctx.fillStyle = data.confidence === "high" || data.confidence === "good" ? t.greenSoft : data.confidence === "fair" ? t.amber : t.subtle;
  ctx.fillText(String(data.confidence || "n/a").toUpperCase(), 56, 504);
  ctx.fillStyle = t.text;
  ctx.fillText(String(data.samples || 0), 270, 504);

  drawLabel(ctx, `Price history — ${(data.series || []).length} pts`, 620, 124, t.muted);
  drawSparkline(ctx, data.series || [], data.median || 0, 620, 146, 524, 300, t);

  drawTopSellers(ctx, data.topSellers || [], 518, t);

  drawFooter(ctx, width, height, t);
}

function composeCompactCard(ctx, data, width, height) {
  const t = themeColors();
  drawHeader(ctx, data, width, t);

  const category = `${data.category || "Item"}${data.tier > 0 ? ` — Tier ${data.tier}` : ""}`;
  drawLabel(ctx, category, 64, 140, t.subtle);

  ctx.font = `900 68px ${SANS}`;
  ctx.fillStyle = t.text;
  const titleHeight = drawTextLines(ctx, data.name || "Unknown item", 64, 196, width - 128, 74, 2);
  let chipX = 64;
  const chipY = 215 + Math.min(titleHeight, 148);
  if (data.tier > 0) {
    chipX += drawChip(ctx, `T${data.tier}`, chipX, chipY, t.amber, t.amber + "1A", t.amber + "66") + 8;
  }
  for (const modifier of (data.modifiers || []).slice(0, 3)) {
    chipX += drawChip(ctx, String(modifier).toUpperCase(), chipX, chipY, t.greenSoft, t.green + "1A", t.green + "66") + 8;
  }

  drawLabel(ctx, "Median price", 64, 410, t.muted);
  ctx.font = `900 108px ${SANS}`;
  ctx.fillStyle = t.green;
  ctx.fillText(data.median > 0 ? fmt(data.median) : "—", 64, 510);

  const trend = trendLabel(data.trend, t);
  ctx.font = `800 18px ${MONO}`;
  ctx.fillStyle = trend.color;
  ctx.fillText(trend.label.toUpperCase(), 64, 552);

  ctx.font = `700 12px ${MONO}`;
  ctx.fillStyle = t.subtle;
  ctx.fillText("CONFIDENCE", 64, 600);
  ctx.fillText("SAMPLES", 320, 600);
  ctx.fillStyle = data.confidence === "high" || data.confidence === "good" ? t.greenSoft : data.confidence === "fair" ? t.amber : t.subtle;
  ctx.fillText(String(data.confidence || "n/a").toUpperCase(), 64, 624);
  ctx.fillStyle = t.text;
  ctx.fillText(String(data.samples || 0), 320, 624);

  drawLabel(ctx, `Price history — ${(data.series || []).length} pts`, 64, 700, t.muted);
  drawSparkline(ctx, data.series || [], data.median || 0, 64, 720, width - 128, 240, t);

  drawFooter(ctx, width, height, t);
}

export function renderCastiaCardToBlob(data, { variant = "item" } = {}) {
  const v = VARIANTS[variant] || VARIANTS.item;
  return new Promise((resolve, reject) => {
    const canvas = document.createElement("canvas");
    canvas.width = v.width;
    canvas.height = v.height;
    const ctx = canvas.getContext("2d");
    if (!ctx) { reject(new Error("Canvas is unavailable")); return; }

    const t = themeColors();
    ctx.fillStyle = t.bg;
    ctx.fillRect(0, 0, v.width, v.height);
    if (v.width >= v.height) {
      drawGlow(ctx, v.width - 270, 60, 520, t.glowGreen, v.width, v.height);
      drawGlow(ctx, 80, v.height - 50, 430, t.glowAmber, v.width, v.height);
    } else {
      drawGlow(ctx, v.width - 80, 80, 520, t.glowGreen, v.width, v.height);
      drawGlow(ctx, 80, v.height - 100, 480, t.glowAmber, v.width, v.height);
    }
    drawGrid(ctx, v.width, v.height, t.gridLine);

    v.compose(ctx, data, v.width, v.height);

    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error("PNG export failed"));
    }, "image/png");
  });
}
