import { useEffect, useState, useMemo, useRef, Fragment } from "react";
import { useNavigate } from "react-router-dom";
import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { Search, Command, Package, User, ArrowRight, Star, Clock, X } from "lucide-react";
import { IS_MAC, CMD_KEY_CHIP } from "@/lib/platform";
import { useMarket } from "@/lib/MarketContext";
import { useWatchlists } from "@/lib/useFavorites";
import { fmt } from "@/lib/parseItem";
import ItemName from "./ItemName";

// Recent-search persistence. Bounded list so the localStorage entry
// stays small; LRU-ish ordering (most recent first).
const RECENT_KEY = "castia.recentSearches";
const RECENT_MAX = 5;
function loadRecent() {
  try {
    const raw = localStorage.getItem(RECENT_KEY);
    const arr = raw ? JSON.parse(raw) : [];
    return Array.isArray(arr) ? arr.filter((s) => typeof s === "string").slice(0, RECENT_MAX) : [];
  } catch { return []; }
}
function saveRecent(list) {
  try { localStorage.setItem(RECENT_KEY, JSON.stringify(list.slice(0, RECENT_MAX))); } catch { /* ignore */ }
}

const ConfDot = ({ conf }) => {
  const map = { high: "bg-emerald-400", good: "bg-lime-400", fair: "bg-amber-400", low: "bg-orange-400", unreliable: "bg-zinc-600" };
  return <span className={`inline-block w-1.5 h-1.5 rounded-full ${map[conf] || "bg-zinc-600"}`}></span>;
};

export default function CommandPalette() {
  const [open, setOpen] = useState(false);
  const [q, setQ] = useState("");
  const [active, setActive] = useState(0);
  const [recent, setRecent] = useState(() => (typeof window === "undefined" ? [] : loadRecent()));
  const inputRef = useRef(null);
  const paletteRef = useRef(null);
  const previousFocusRef = useRef(null);
  const navigate = useNavigate();
  const { market, sellers } = useMarket();
  const watchlists = useWatchlists();
  const prefersReduced = useReducedMotion();

  // Global ⌘K / Ctrl+K to toggle
  useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "k") {
        e.preventDefault();
        setOpen((s) => !s);
      } else if (e.key === "/" && !open) {
        const tag = (document.activeElement?.tagName || "").toLowerCase();
        if (tag === "input" || tag === "textarea" || tag === "select") return;
        e.preventDefault();
        setOpen(true);
      } else if (e.key === "Escape" && open) {
        if (q) {
          setQ("");
          setActive(0);
        } else {
          setOpen(false);
        }
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [open, q]);

  // Store previous focus and focus input on open; restore focus on close
  useEffect(() => {
    if (open) {
      previousFocusRef.current = document.activeElement;
      setQ("");
      setActive(0);
      setTimeout(() => inputRef.current?.focus(), 60);
    }
    if (!open && previousFocusRef.current && document.activeElement !== previousFocusRef.current) {
      previousFocusRef.current?.focus();
    }
  }, [open]);

  // Focus trap while open
  useEffect(() => {
    if (!open) return;
    const palette = paletteRef.current;
    if (!palette) return;
    const onKeyDown = (e) => {
      if (e.key !== "Tab") return;
      const focusable = palette.querySelectorAll(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
      );
      if (focusable.length === 0) return;
      const first = focusable[0];
      const last = focusable[focusable.length - 1];
      if (e.shiftKey) {
        if (document.activeElement === first) {
          e.preventDefault();
          last.focus();
        }
      } else {
        if (document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      }
    };
    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [open]);

  const results = useMemo(() => {
    const itemRows = market?.rows || [];
    const sellerRows = sellers || [];
    const ql = q.trim().toLowerCase();
    if (!ql) {
      // Empty input — surface recent searches as a separate section
      // so the user can re-run a prior query with one click.
      const recentHits = recent
        .map((term) => {
          const ql2 = term.toLowerCase();
          const items = itemRows
            .filter((r) =>
              r.name.toLowerCase().includes(ql2) ||
              r.key.toLowerCase().includes(ql2) ||
              r.category.toLowerCase().includes(ql2) ||
              (r.modifiers || []).some((m) => m.toLowerCase().includes(ql2)),
            )
            .slice(0, 3)
            .map((r) => ({ type: "item", row: r, label: `Recent: ${term}` }));
          const sellersMatch = sellerRows
            .filter((s) => s.name.toLowerCase().includes(ql2))
            .slice(0, 2)
            .map((s) => ({ type: "seller", row: s, label: `Recent: ${term}` }));
          return { term, hits: [...items, ...sellersMatch] };
        })
        .filter((b) => b.hits.length > 0);

      const favItems = itemRows.filter((r) => watchlists.has(r.key)).slice(0, 5);
      const topItems = [...itemRows].sort((a, b) => b.samples - a.samples).slice(0, 5);
      const topSellers = sellerRows.slice(0, 3);

      return {
        groups: [
          ...recentHits.map((b) => ({ kind: "section", label: b.term, hits: b.hits })),
          { kind: "section", label: "Favorites", hits: favItems.map((r) => ({ type: "item", row: r, label: "Favorite" })) },
          { kind: "section", label: "Popular",   hits: topItems.map((r) => ({ type: "item", row: r, label: "Popular" })) },
          { kind: "section", label: "Top sellers", hits: topSellers.map((s) => ({ type: "seller", row: s, label: "Top seller" })) },
        ],
      };
    }
    // Active query: group items by category (alpha-sorted within),
    // then append sellers in a final group. Categories give the
    // list a visual rhythm when results span multiple item types.
    const items = itemRows
      .filter((r) =>
        r.name.toLowerCase().includes(ql) ||
        r.key.toLowerCase().includes(ql) ||
        r.category.toLowerCase().includes(ql) ||
        (r.modifiers || []).some((m) => m.toLowerCase().includes(ql)),
      )
      .slice(0, 16);
    const byCategory = new Map();
    for (const r of items) {
      const cat = r.category || "Misc";
      if (!byCategory.has(cat)) byCategory.set(cat, []);
      byCategory.get(cat).push(r);
    }
    const itemGroups = [...byCategory.entries()]
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([cat, rows]) => ({
        kind: "section",
        label: cat,
        hits: rows.map((r) => ({ type: "item", row: r })),
      }));
    const sellerHits = sellerRows
      .filter((s) => s.name.toLowerCase().includes(ql))
      .slice(0, 5)
      .map((s) => ({ type: "seller", row: s }));
    const sellerGroup = sellerHits.length
      ? [{ kind: "section", label: "Sellers", hits: sellerHits }]
      : [];
    return { groups: [...itemGroups, ...sellerGroup] };
  }, [q, market, sellers, watchlists, recent]);

  // Flat list of (group, idx-in-group, hit) for keyboard nav. The
  // active index is the position in this flat list.
  const flat = useMemo(() => {
    const out = [];
    for (const g of results.groups) {
      for (const h of g.hits) out.push({ group: g, hit: h });
    }
    return out;
  }, [results]);
  // Reset active when the result set changes.
  useEffect(() => { setActive(0); }, [q, open]);

  const pushRecent = (query) => {
    const term = query.trim();
    if (!term) return;
    const next = [term, ...recent.filter((s) => s !== term)].slice(0, RECENT_MAX);
    setRecent(next);
    saveRecent(next);
  };

  const choose = (idx) => {
    const entry = flat[idx];
    if (!entry) return;
    if (q.trim()) pushRecent(q);
    if (entry.hit.type === "item") navigate(`/item/${encodeURIComponent(entry.hit.row.key)}`);
    else navigate(`/sellers/${encodeURIComponent(entry.hit.row.name)}`);
    setOpen(false);
  };

  const clearRecent = () => {
    setRecent([]);
    saveRecent([]);
  };

  const handleKey = (e) => {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setActive((a) => Math.min(flat.length - 1, a + 1));
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setActive((a) => Math.max(0, a - 1));
    } else if (e.key === "Home") {
      e.preventDefault();
      setActive(0);
    } else if (e.key === "End") {
      e.preventDefault();
      setActive(Math.max(0, flat.length - 1));
    } else if (e.key === "Enter") {
      e.preventDefault();
      choose(active);
    }
  };

  // Index within a section, used for the data-testid of each row.
  // The flat list advances by 1 per hit; the section counter resets.
  let flatIdx = -1;

  return (
    <AnimatePresence>
      {open && (
        <motion.div
          key="cmdk-overlay"
          initial={prefersReduced ? undefined : { opacity: 0 }}
          animate={prefersReduced ? undefined : { opacity: 1 }}
          exit={prefersReduced ? undefined : { opacity: 0 }}
          transition={{ duration: 0.18 }}
          className="fixed inset-0 z-[60] drawer-backdrop flex justify-center items-start pt-[12vh]"
          onClick={() => setOpen(false)}
          data-testid="command-palette-overlay"
          role="dialog"
          aria-modal="true"
          aria-label="Command palette"
        >
          <motion.div
            ref={paletteRef}
            initial={prefersReduced ? undefined : { y: -10, scale: 0.96, opacity: 0 }}
            animate={prefersReduced ? undefined : { y: 0, scale: 1, opacity: 1 }}
            exit={prefersReduced ? undefined : { y: -10, scale: 0.96, opacity: 0 }}
            transition={{ duration: 0.22, ease: [0.16, 1, 0.3, 1] }}
            onClick={(e) => e.stopPropagation()}
            data-testid="command-palette"
            className="w-[min(640px,100%)] mx-4 bg-bg-base border border-white/15 rounded-2xl shadow-[0_30px_80px_rgba(0,0,0,0.7)] overflow-hidden"
          >
            <div className="flex items-center gap-3 px-5 py-4 border-b border-white/10">
              <Search className="w-4 h-4 text-zinc-500 shrink-0" />
              <input
                ref={inputRef}
                value={q}
                onChange={(e) => setQ(e.target.value)}
                onKeyDown={handleKey}
                placeholder="Search items or sellers…"
                aria-label="Search items or sellers"
                role="combobox"
                aria-expanded={flat.length > 0}
                aria-haspopup="listbox"
                aria-controls="cmdk-results-list"
                aria-activedescendant={flat.length > 0 ? `cmdk-option-${active}` : undefined}
                data-testid="cmdk-input"
                className="flex-1 bg-transparent outline-none placeholder-zinc-600 text-white font-body text-base"
              />
              <span className="kbd">ESC</span>
            </div>
            <div id="cmdk-results-list" role="listbox" className="max-h-[60vh] overflow-y-auto no-scrollbar p-2" data-testid="cmdk-results">
              {flat.length === 0 && (
                <div className="px-5 py-12 text-center font-mono text-xs uppercase tracking-wider text-zinc-500" data-testid="cmdk-empty">
                  {q ? `No matches for "${q}"` : "Start typing to search"}
                </div>
              )}
              {results.groups.map((g) => {
                if (g.hits.length === 0) return null;
                return (
                  <Fragment key={g.label}>
                    <div
                      data-testid={`cmdk-section-${g.label.toLowerCase().replace(/\s+/g, "-")}`}
                      className="flex items-center justify-between px-3 pt-3 pb-1 font-mono text-[10px] uppercase tracking-wider text-zinc-500"
                    >
                      <span>{g.label}</span>
                      {!q && g.label === recent[0] && recent.length > 0 && (
                        <button
                          onClick={clearRecent}
                          data-testid="cmdk-clear-recent"
                          className="inline-flex items-center gap-1 text-zinc-600 hover:text-red-400 transition-colors normal-case tracking-normal"
                          title="Clear recent searches"
                        >
                          <X className="w-3 h-3" /> Clear
                        </button>
                      )}
                    </div>
                    {g.hits.map((h) => {
                      flatIdx += 1;
                      const i = flatIdx;
                      const isActive = active === i;
                      return (
                        <button
                          key={`${h.type}-${h.row.key || h.row.name}-${i}`}
                          id={`cmdk-option-${i}`}
                          role="option"
                          aria-selected={isActive}
                          data-testid={`cmdk-result-${i}`}
                          onMouseEnter={() => setActive(i)}
                          onClick={() => choose(i)}
                          className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-left transition-colors ${
                            isActive ? "bg-emerald-500/10" : "hover:bg-white/[0.04]"
                          }`}
                        >
                          <div className="w-9 h-9 rounded-md grid place-items-center bg-white/[0.04] shrink-0">
                            {h.type === "item" ? (
                              <Package className="w-4 h-4 text-emerald-400" />
                            ) : (
                              <User className="w-4 h-4 text-amber-400" />
                            )}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 min-w-0">
                              <div className="font-medium text-white truncate">
                                {h.type === "item" ? <ItemName name={h.row.name} tier={h.row.tier} modifiers={h.row.modifiers} /> : h.row.name}
                              </div>
                              {h.type === "item" && watchlists.has(h.row.key) && (
                                <Star className="w-3 h-3 text-amber-400 fill-amber-400 shrink-0" />
                              )}
                              {!q && h.label?.startsWith("Recent:") && (
                                <Clock className="w-3 h-3 text-zinc-600 shrink-0" />
                              )}
                            </div>
                            <div className="font-mono text-[10px] uppercase tracking-wider text-zinc-500 truncate">
                              {h.type === "item"
                                ? <>{h.row.category} <span className="text-zinc-700">·</span> <ConfDot conf={h.row.conf || h.row.confidence} /> {h.row.confidence}</>
                                : <>{h.row.accuracyLabel} <span className="text-zinc-700">·</span> {h.row.totalListings} listings</>
                              }
                            </div>
                          </div>
                          {h.type === "item" && (
                            <div className="font-mono text-sm tabular text-white shrink-0">{fmt(h.row.median)}</div>
                          )}
                          {h.label && !h.label.startsWith("Recent:") && (
                            <span className="font-mono text-[9px] uppercase tracking-wider text-zinc-600 ml-2 shrink-0">{h.label}</span>
                          )}
                          <ArrowRight className="w-3.5 h-3.5 text-zinc-600 shrink-0" />
                        </button>
                      );
                    })}
                  </Fragment>
                );
              })}
            </div>
            <div className="px-5 py-3 border-t border-white/10 flex items-center justify-between font-mono text-[10px] uppercase tracking-wider text-zinc-500">
              <div className="flex items-center gap-3">
                <span className="inline-flex items-center gap-1.5"><span className="inline-flex items-center gap-0.5"><span className="kbd">↑</span><span className="kbd">↓</span></span> nav</span>
                <span className="inline-flex items-center gap-1.5"><span className="kbd">↵</span> open</span>
                <span className="inline-flex items-center gap-1.5"><span className="kbd">esc</span> {q ? "clear" : "close"}</span>
              </div>
              <span className="inline-flex items-center gap-1.5">
                {IS_MAC
                  ? <Command className="w-3 h-3" />
                  : <span className="kbd">{CMD_KEY_CHIP}</span>}
                + <span className="kbd">k</span> to summon
              </span>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
